const body = $input.first().json.body ?? $input.first().json;
if (!body || !Array.isArray(body.leads)) throw new Error('The leads field must be an array.');
if (body.leads.length === 0) throw new Error('At least one lead is required.');
if (body.leads.length > 5000) throw new Error('A maximum of 5000 leads may be imported at once.');
const fields = ['firstName','lastName','company','website','email','industry','services','leadId','status'];
for (const lead of body.leads) {
  if (!lead || typeof lead !== 'object' || !fields.every((field) => typeof lead[field] === 'string')) {
    throw new Error('Every lead must contain the expected string fields.');
  }
}
return [{ json: { leads: body.leads, total: body.leads.length } }];

const request = $('Validate Payload').first().json;
const existing = $input.all().map((item) => item.json);
const norm = (value) => String(value ?? '').trim().toLowerCase().replace(/\s+/g, ' ');
const normWebsite = (value) => norm(value).replace(/^https?:\/\//, '').replace(/^www\./, '').replace(/\/$/, '');
const emails = new Set(existing.map((row) => norm(row.Email)).filter(Boolean));
const websites = new Set(existing.map((row) => normWebsite(row.Website)).filter(Boolean));
const companies = new Set(existing.map((row) => norm(row['Business Name'])).filter(Boolean));
const seen = new Set();
const accepted = [];
let duplicates = 0;
let invalid = 0;
for (const raw of request.leads) {
  const lead = { ...raw, email: norm(raw.email), website: String(raw.website ?? '').trim(), company: String(raw.company ?? '').trim() };
  if (!lead.email && !lead.website && !lead.company) { invalid++; continue; }
  if (lead.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(lead.email)) { invalid++; continue; }
  const key = lead.email ? `email:${lead.email}` : lead.website ? `website:${normWebsite(lead.website)}` : `company:${norm(lead.company)}`;
  const exists = lead.email ? emails.has(lead.email) : lead.website ? websites.has(normWebsite(lead.website)) : companies.has(norm(lead.company));
  if (seen.has(key) || exists) { duplicates++; continue; }
  seen.add(key);
  accepted.push(lead);
}
const meta = { total: request.total, duplicates, invalid, valid: accepted.length };
if (accepted.length === 0) return [{ json: { _skip: true, _meta: meta } }];
return accepted.map((lead) => ({ json: { ...lead, _skip: false, _meta: meta } }));

const results = $input.all();
const meta = $('Validate and Deduplicate').first().json._meta;
const failed = results.filter((item) => item.json.error || item.json.message?.toLowerCase?.().includes('error')).length;
const imported = Math.max(0, meta.valid - failed);
return [{ json: { success: true, summary: { total: meta.total, imported, duplicates: meta.duplicates, invalid: meta.invalid, failed } } }];
